{
  "executive_summary": "Design a unified API Gateway architecture for a logistics platform serving three distinct consumer types (mobile, B2B partner, internal). The gateway centralizes authentication, rate limiting, and traffic isolation — replacing the current inconsistent per-service implementations. A single gateway with three listener entry points provides clean separation without the operational burden of multiple gateway instances.",

  "architecture": {
    "components": [
      {
        "name": "API Gateway (Edge)",
        "responsibility": "Single deployment with three logical listeners: public (mobile), partner (B2B), internal. Handles TLS termination, request routing, observability (access logs, distributed tracing headers), and request/response transformation.",
        "boundaries": "Sits at the network edge. Owns NO business logic. Performs only cross-cutting concerns: auth, rate limiting, routing, circuit breaking. Must never become a 'smart pipe'."
      },
      {
        "name": "Auth Plugin — Mobile (JWT/OAuth2)",
        "responsibility": "Validates JWT tokens issued by the Identity Provider. Extracts user ID claim for per-user rate limiting. Rejects expired/malformed tokens at the gateway before traffic reaches services.",
        "boundaries": "Stateless validation only. Does not issue tokens — that remains the Identity Provider's job."
      },
      {
        "name": "Auth Plugin — Partner (API Key + HMAC)",
        "responsibility": "Validates API keys against a partner registry. Optionally verifies HMAC request signatures for tamper protection. Injects partner ID header for downstream services.",
        "boundaries": "API key lookup should use a low-latency cache (Redis) with TTL-based invalidation. Key issuance/rotation is handled by the Partner Portal, not the gateway."
      },
      {
        "name": "Rate Limiter",
        "responsibility": "Enforces rate limits using a sliding window counter backed by Redis. Mobile: 100 req/min keyed by user ID. Partner: 1,000 req/min keyed by partner ID. Internal: no limit. Returns 429 with Retry-After header.",
        "boundaries": "Shared Redis instance for distributed counting across gateway replicas. Rate limit configuration is externalized (not hardcoded)."
      },
      {
        "name": "Webhook Dispatcher",
        "responsibility": "Consumes domain events from an internal message bus (e.g., shipment.delivered, order.status_changed) and delivers them to partner-registered webhook URLs with retry logic, HMAC signing of payloads, and delivery logging.",
        "boundaries": "Runs as a separate service behind the gateway — NOT inside the gateway process. Owns the outbound delivery contract but not the event production."
      },
      {
        "name": "Internal Mesh / Private Listener",
        "responsibility": "Accepts traffic only from the internal network (VPC/private subnet). No authentication required. Provides service-to-service routing with the same observability (tracing, logging) as external paths.",
        "boundaries": "Isolated at the network level — no public DNS, no internet-facing ingress. Enforced by network policy (security groups / Kubernetes NetworkPolicy), not application logic."
      },
      {
        "name": "Partner Registry",
        "responsibility": "Stores partner API keys, rate limit overrides, webhook subscriptions, and allowed scopes. Provides a CRUD API for the Partner Portal.",
        "boundaries": "Source of truth for partner configuration. Gateway reads from its cache; Partner Portal writes to it."
      },
      {
        "name": "Identity Provider (existing)",
        "responsibility": "Issues and refreshes JWT tokens for mobile users. Manages user authentication (password, social, MFA).",
        "boundaries": "Upstream of the gateway. Gateway is a consumer of its public keys (JWKS endpoint) for token validation."
      }
    ],
    "interfaces": [
      {
        "from": "Mobile App",
        "to": "API Gateway (public listener, port 443)",
        "contract": "HTTPS + Bearer JWT in Authorization header. Gateway validates JWT, extracts user_id, enforces 100 req/min, proxies to upstream service with X-User-Id header.",
        "coupling_type": "loose — standard OAuth2 bearer token contract"
      },
      {
        "from": "Partner Systems",
        "to": "API Gateway (partner listener, port 443, /partner/* path prefix)",
        "contract": "HTTPS + X-API-Key header (+ optional X-Signature HMAC). Gateway validates key, enforces 1,000 req/min, proxies to upstream with X-Partner-Id header.",
        "coupling_type": "loose — API key is an opaque credential, HMAC is optional"
      },
      {
        "from": "Internal Services",
        "to": "API Gateway (private listener, port 8080, internal-only network)",
        "contract": "HTTP (TLS optional within mesh) with no auth headers required. Gateway adds tracing headers and proxies to upstream. Network-level isolation enforced.",
        "coupling_type": "minimal — no auth coupling, just routing"
      },
      {
        "from": "API Gateway",
        "to": "Upstream Services",
        "contract": "Gateway strips external auth tokens, injects trusted headers (X-User-Id, X-Partner-Id, X-Consumer-Type). Upstream services trust the gateway and ONLY accept traffic from it (enforced by network policy).",
        "coupling_type": "moderate — upstream services depend on gateway-injected headers"
      },
      {
        "from": "API Gateway (Rate Limiter)",
        "to": "Redis",
        "contract": "Sliding window counter using MULTI/EXEC. Key pattern: ratelimit:{consumer_type}:{id}:{window}. TTL matches window size.",
        "coupling_type": "infrastructure coupling — Redis is a critical dependency"
      },
      {
        "from": "Webhook Dispatcher",
        "to": "Partner Systems (outbound)",
        "contract": "POST to partner-registered URL. JSON payload with HMAC-SHA256 signature in X-Webhook-Signature header. Exponential backoff retry (1s, 5s, 30s, 5m, 30m). Dead-letter after 5 failures.",
        "coupling_type": "loose — fire-and-forget with retry"
      },
      {
        "from": "Domain Services",
        "to": "Webhook Dispatcher",
        "contract": "Publishes domain events to message bus (e.g., SNS/SQS, Kafka, or NATS topic). Dispatcher subscribes and fans out to relevant partners.",
        "coupling_type": "decoupled — async via message bus"
      }
    ],
    "data_flow": "Mobile/Partner requests → DNS → Load Balancer → API Gateway listener (public or partner) → Auth plugin validates credentials → Rate limiter checks/increments counter in Redis → Request proxied to upstream service with trusted identity headers → Response flows back through gateway (with optional response transformation). Internal requests → Private LB → Internal gateway listener → Direct proxy to upstream (no auth, no rate limit). Webhook flow: Upstream service emits domain event → Message bus → Webhook Dispatcher → Partner endpoint.",
    "patterns_used": [
      {
        "pattern": "API Gateway (Edge)",
        "rationale": "Centralizes cross-cutting concerns that are currently inconsistently implemented across services. Eliminates duplication, enforces consistency, and provides a single control plane for auth and rate limiting."
      },
      {
        "pattern": "Backends for Frontends (BFF) — lightweight variant",
        "rationale": "Three logical listeners on one gateway achieve consumer-specific behavior (different auth, different limits) without deploying three separate gateways. If mobile needs diverge significantly later, this can split into a full BFF."
      },
      {
        "pattern": "Sliding Window Rate Limiting",
        "rationale": "More accurate than fixed-window counters (avoids burst-at-boundary). Redis-backed for distributed consistency across gateway replicas."
      },
      {
        "pattern": "Strangler Fig (migration strategy)",
        "rationale": "Services currently handle auth independently. Gateway should be introduced incrementally — route one service at a time through the gateway while keeping existing auth as a fallback, then remove per-service auth once gateway routing is proven."
      },
      {
        "pattern": "Network-Level Isolation",
        "rationale": "Internal traffic isolation via network policy is far more reliable than application-level checks. Internal listener binds to a private interface that is unreachable from the internet — defense in depth."
      },
      {
        "pattern": "Async Webhook Delivery via Message Bus",
        "rationale": "Decouples webhook delivery from the request path. Domain services publish events without knowing about partners. Dispatcher handles fan-out, retries, and failure isolation independently."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Gateway & Traffic Management",
        "classification": "generic",
        "aggregates": ["GatewayRoute", "RateLimitPolicy", "ConsumerIdentity"]
      },
      {
        "name": "Partner Integration",
        "classification": "supporting",
        "aggregates": ["Partner", "APIKey", "WebhookSubscription", "WebhookDelivery"]
      },
      {
        "name": "Identity & Access",
        "classification": "generic",
        "aggregates": ["User", "Session", "Token"]
      },
      {
        "name": "Logistics Core (upstream services)",
        "classification": "core",
        "aggregates": ["Shipment", "Order", "Route"]
      }
    ],
    "context_map": [
      {
        "upstream": "Identity & Access",
        "downstream": "Gateway & Traffic Management",
        "relationship": "Conformist — Gateway conforms to the IdP's JWT format and JWKS endpoint. No translation layer needed."
      },
      {
        "upstream": "Partner Integration",
        "downstream": "Gateway & Traffic Management",
        "relationship": "Customer-Supplier — Partner context defines API keys and rate limit overrides; Gateway consumes them via cache. Gateway team can request schema changes."
      },
      {
        "upstream": "Logistics Core",
        "downstream": "Partner Integration (Webhook Dispatcher)",
        "relationship": "Published Language — Core publishes domain events in a documented schema. Webhook Dispatcher translates events into partner-facing webhook payloads (ACL)."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single gateway deployment with multiple listeners vs. separate gateway per consumer type",
      "gains": "Lower operational overhead (one deployment, one config surface, one monitoring dashboard). Shared infrastructure (Redis, logging). Simpler to maintain for a team that currently has no gateway experience.",
      "sacrifices": "Less blast radius isolation — a gateway bug affects all consumers. Slightly more complex routing config within one deployment.",
      "alternatives_considered": [
        "Three separate gateway instances (full BFF) — rejected for now due to operational burden, but the architecture supports splitting later if needed",
        "Service mesh (e.g., Istio) instead of gateway — rejected because it solves a different problem (east-west traffic) and doesn't natively handle API key auth or webhook delivery"
      ]
    },
    {
      "decision": "Redis-backed sliding window rate limiter vs. local in-memory rate limiting",
      "gains": "Accurate distributed rate limiting across all gateway replicas. Consistent enforcement regardless of which replica handles the request.",
      "sacrifices": "Adds Redis as a critical-path dependency. ~1ms latency per rate limit check. Requires Redis HA (Sentinel or Cluster).",
      "alternatives_considered": [
        "Local in-memory counters with approximate distributed sync — simpler but allows burst overages proportional to replica count",
        "Token bucket algorithm — viable alternative, chose sliding window for more intuitive configuration (X requests per Y minutes)"
      ]
    },
    {
      "decision": "Gateway strips external tokens and injects trusted headers vs. passing tokens through",
      "gains": "Upstream services have a uniform, simple contract (read X-User-Id / X-Partner-Id headers). Services don't need auth libraries. Clear trust boundary at the gateway.",
      "sacrifices": "Services become fully dependent on the gateway for identity. Cannot operate standalone without it (acceptable since the gateway IS the entry point).",
      "alternatives_considered": [
        "Pass tokens through and let services validate — rejected because this is exactly the current broken pattern",
        "Re-sign with an internal JWT — more flexible but unnecessary complexity for a single-team deployment"
      ]
    },
    {
      "decision": "Strangler Fig migration vs. big-bang cutover",
      "gains": "Low risk. Each service can be migrated independently. Rollback is trivial (revert DNS/routing). Team builds confidence incrementally.",
      "sacrifices": "Temporary period where some services are behind the gateway and some aren't. Slightly more complex networking during transition.",
      "alternatives_considered": [
        "Big-bang cutover — rejected due to high risk with no existing gateway experience on the team"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Rate limit configuration",
      "evolution_path": "Rate limits are externalized config (not hardcoded). Can add per-endpoint limits, burst allowances, or partner-specific overrides without code changes. Future: dynamic rate limiting based on system load."
    },
    {
      "area": "Consumer-specific listeners → full BFF split",
      "evolution_path": "If mobile and partner APIs diverge significantly (different response shapes, different caching strategies), split the single gateway into dedicated BFF gateways. The three-listener architecture is designed to make this split clean."
    },
    {
      "area": "Webhook event types",
      "evolution_path": "New domain events can be added to webhook delivery by subscribing the dispatcher to additional message bus topics. Partners can subscribe to specific event types. No gateway changes needed."
    },
    {
      "area": "Auth mechanisms",
      "evolution_path": "Gateway plugin architecture allows adding new auth methods (mTLS for partners, OIDC federation) without modifying core routing logic."
    }
  ],

  "rigidity_points": [
    {
      "area": "Gateway as single entry point for external traffic",
      "reason": "All external traffic MUST flow through the gateway. This is intentionally rigid — it's the security perimeter. Allowing bypass routes would undermine the entire architecture."
    },
    {
      "area": "Trusted header contract (X-User-Id, X-Partner-Id, X-Consumer-Type)",
      "reason": "Upstream services depend on these headers for identity. Changing the header names or semantics requires coordinated updates. This rigidity is acceptable because the contract is simple and well-defined."
    },
    {
      "area": "Network isolation of internal listener",
      "reason": "Internal traffic isolation is enforced at the network layer, not the application layer. Changing this requires infrastructure changes (security groups, network policies), which is intentionally rigid for security."
    }
  ],

  "risks": [
    {
      "risk": "Gateway becomes a single point of failure for all external traffic",
      "severity": "critical",
      "mitigation": "Deploy gateway with at least 3 replicas across availability zones. Use health-check-based load balancing. Implement circuit breakers on upstream calls so one failing service doesn't cascade. Monitor gateway latency p99 and error rate with alerts."
    },
    {
      "risk": "Redis failure causes rate limiter to either block all traffic or allow unlimited traffic",
      "severity": "high",
      "mitigation": "Deploy Redis with Sentinel or Cluster for HA. Implement a fail-open policy with degraded rate limiting (local in-memory fallback with conservative limits). Log all fallback events for audit."
    },
    {
      "risk": "Strangler Fig migration leaves some services behind the gateway and some not — inconsistent security posture during transition",
      "severity": "high",
      "mitigation": "Prioritize migrating the most security-sensitive services first. Set a firm deadline (e.g., 4 sprints) to complete migration. Block direct external access to migrated services via network policy immediately upon migration."
    },
    {
      "risk": "Gateway latency overhead degrades mobile app experience",
      "severity": "medium",
      "mitigation": "Target < 5ms added latency at p99 (JWT validation ~1ms, rate limit check ~1ms, routing ~1ms). Load test before production rollout. The latency savings from removing per-service auth may offset gateway overhead."
    },
    {
      "risk": "Webhook delivery failures cause partner data sync issues",
      "severity": "medium",
      "mitigation": "Exponential backoff with dead-letter queue. Partner dashboard showing delivery status and allowing manual retry. Webhook delivery SLA documented in partner agreement (e.g., 99.5% delivery within 5 minutes)."
    },
    {
      "risk": "Team has no gateway operational experience — initial misconfiguration risk",
      "severity": "medium",
      "mitigation": "Start with a proven gateway (Kong, AWS API Gateway, or Envoy-based). Use infrastructure-as-code for gateway config. Invest in runbooks for common failure scenarios before go-live."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (Weeks 1-2): Deploy gateway infrastructure with the internal listener only. Route one low-risk internal service through it. Validate observability (logging, tracing, metrics). Phase 2 (Weeks 3-4): Enable mobile listener with JWT validation. Migrate one mobile-facing service using Strangler Fig (dual routing with gateway as primary, direct as fallback). Enable rate limiting. Phase 3 (Weeks 5-6): Enable partner listener with API key auth. Migrate partner-facing services. Phase 4 (Weeks 7-8): Deploy Webhook Dispatcher. Integrate with message bus. Onboard first partner to webhooks. Phase 5 (Weeks 9-10): Complete migration of all remaining services. Remove per-service auth code. Lock down network policies to prevent gateway bypass.",
    "files_to_create_or_modify": [
      "infrastructure/gateway/gateway.yaml — Gateway deployment config (listeners, routes, plugins)",
      "infrastructure/gateway/rate-limit-policies.yaml — Externalized rate limit configuration per consumer type",
      "infrastructure/gateway/auth-plugins/ — JWT and API Key plugin configurations",
      "infrastructure/redis/redis-ha.yaml — Redis Sentinel/Cluster deployment for rate limiting",
      "infrastructure/network-policies/ — NetworkPolicy manifests isolating internal listener and blocking direct service access",
      "services/webhook-dispatcher/ — New service: event consumer, delivery engine, retry logic, dead-letter handling",
      "services/partner-registry/ — New or modified service: API key CRUD, webhook subscription management",
      "docs/adr/001-api-gateway-introduction.md — Architecture Decision Record documenting this design",
      "docs/runbooks/gateway-failure-scenarios.md — Operational runbook for gateway incidents"
    ],
    "patterns_to_follow": "Use declarative gateway configuration (infrastructure-as-code, not click-ops). All gateway plugins should be stateless — state lives in Redis or the partner registry. Upstream services must validate the X-Consumer-Type header as a defense-in-depth measure even though network policy is the primary control. Use structured logging with correlation IDs that flow from gateway to upstream services. Rate limit responses must include X-RateLimit-Limit, X-RateLimit-Remaining, and Retry-After headers per RFC 6585.",
    "pitfalls_to_avoid": [
      "Do NOT put business logic in the gateway — it routes and enforces cross-cutting policies, nothing more. The moment you add request transformation that requires domain knowledge, you've created a distributed monolith.",
      "Do NOT hardcode rate limits — externalize them so ops can adjust without redeployment.",
      "Do NOT rely solely on application-level checks for internal traffic isolation — network policy is the primary control, application checks are defense-in-depth.",
      "Do NOT skip the Strangler Fig approach and try a big-bang migration — the team has no gateway experience and needs to build operational confidence incrementally.",
      "Do NOT use a synchronous HTTP call from domain services to the webhook dispatcher — use the message bus. Synchronous coupling here would make webhook delivery a latency contributor on the main request path.",
      "Do NOT store API keys in plaintext — hash them (SHA-256 with a prefix for lookup). The gateway checks the hash, not the raw key."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "Gateway as the right solution for centralizing auth and rate limiting — the current per-service approach is a well-known anti-pattern with clear downsides",
      "Three-listener architecture with network-level isolation for internal traffic",
      "Strangler Fig migration strategy — proven approach for introducing a gateway incrementally",
      "Async webhook delivery via message bus — standard pattern for partner integrations"
    ],
    "low_confidence_areas": [
      "Specific gateway technology choice (Kong vs Envoy vs cloud-native) — depends on team expertise and infrastructure platform, which are unknown",
      "Exact Redis topology — Sentinel vs Cluster depends on scale and existing infrastructure",
      "Whether the team needs a dedicated Partner Portal service or can extend an existing admin service"
    ],
    "assumptions": [
      "The platform runs on Kubernetes or a similar orchestration platform that supports NetworkPolicy for traffic isolation",
      "A message bus (Kafka, SQS, NATS, etc.) either exists or can be introduced for webhook event delivery",
      "The existing Identity Provider exposes a JWKS endpoint for JWT validation",
      "The team is small enough that a single gateway deployment (vs. per-team gateways) is operationally appropriate",
      "Partner count is in the hundreds, not tens of thousands — the API key lookup pattern scales to this level without specialized infrastructure"
    ]
  }
}

